var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"KNIGHT_NPC_NULL_NULL","text":{"KOREA":"크륵, 크으으……!","JPN":"グルル、グウウ……！","ENG":"Grrr, Khhhkkk...!","TWN":"咳呃，咳呃呃……！"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"THEMA_CS_ELECTRIC","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KNIGHT_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}},"sfx":"FX_COMBAT_MONSTER_PAWN_DAMAGE_DOWN"},{"id":"L4_1","type":"dialog","speaker":"KNIGHT_NPC_NULL_NULL","text":{"KOREA":"구원이…… 구원을 위해……!","JPN":"救いが……救いのために……！","ENG":"Salvation... For salvation...!","TWN":"為了……為了救贖……！"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"THEMA_CS_ELECTRIC","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"KNIGHT_NPC_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_COMBAT_MONSTER_PAWN_DAMAGE_DOWN"},{"id":"L6_1","type":"dialog","speaker":"NINA_FRONTIER_NULL_NULL","text":{"KOREA":"공개 회선으로 전한다! 적들의 상태가 갑자기 이상해졌어!","JPN":"公開回線を通じて伝える！　敵の様子が急におかしくなった！","ENG":"Announcing through public channel! The enemy is behaving weirdly!","TWN":"這是來自公共頻道的通知——敵人的狀態突然變得很奇怪！"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"THEMA_CS_ELECTRIC","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NINA_FRONTIER_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_PHONE"},{"id":"L7_1","type":"dialog","speaker":"LEE_FRONTIER_NULL_NULL","text":{"KOREA":"절대 거리를 주지 마! 함부로 접근하게 놔뒀다간 뼈도 못 추려!","JPN":"決して距離を詰められるな！　無闇に接近しようものならひとたまりもない！","ENG":"Do not let them get close! The minute they close in, you won't last a second!","TWN":"不要給他們縮短距離的機會！要是放任他們接近，後果很危險！"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"THEMA_CS_ELECTRIC","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEE_FRONTIER_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_PHONE"},{"id":"L12_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"침식체로서 본색을 드러내기 시작했네요.","JPN":"侵食体としての本性を現し始めましたね。","ENG":"They started to reveal their true forms as C.O.s.","TWN":"終於開始露出侵蝕體的真面目了。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"THEMA_CS_ELECTRIC","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"진형은 흐트러지지 않는 걸 봐선… 적의 지휘관이 전황을 위험하다고 판단한 거겠죠.","JPN":"陣形が崩れていないということは……敵の指揮官が戦況を危ないと判断したんでしょうね。","ENG":"Seeing that their formation is intact... Their commander must have considered this situation as a threat.","TWN":"但是隊形還沒有散開……就表示敵人的指揮官認為戰況危急吧？"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"THEMA_CS_ELECTRIC","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"KNIGHT_NPC_ZODIAC_A","text":{"KOREA":"대체 뭐야? 갑옷도 무기도, 우리와 똑같아.","JPN":"いったいなんだ？　鎧も武器も、俺たちとそっくりだ。","ENG":"What is that? They have the same weapons and armor as us.","TWN":"究竟是怎麼回事？鎧甲還有武器，都和我們一模一樣。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"THEMA_CS_ELECTRIC","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_NPC_ZODIAC_A","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"KNIGHT_NPC_ZODIAC_A","text":{"KOREA":"역시 레드시프트 놈들이 관여한 것 아닐까?","JPN":"やっぱりレッドシフトの連中が関与しているんじゃ？","ENG":"Maybe Red Shift did interfere with this.","TWN":"他們會不會是紅移的那些傢伙？"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"THEMA_CS_ELECTRIC","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_NPC_ZODIAC_A","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"KNIGHT_NPC_ZODIAC_A","text":{"KOREA":"아무리 그 자들이라도 그렇지, 이건 너무 지나치잖아…….","JPN":"さすがの奴らでも、これは酷すぎるぜ……","ENG":"But this is too much, even for them...","TWN":"就算是那些人，這樣也太過分了吧……"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"THEMA_CS_ELECTRIC","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_NPC_ZODIAC_A","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NULL_NULL","text":{"KOREA":"……차마 눈 뜨고 볼 수 없군. 이건 기사의 정신을 모욕하는 행위다.","JPN":"……目も当てられないな。これは騎士の精神を侮辱する行為だ。","ENG":"...I can't bear to look at this. This is an insult to chivalry.","TWN":"……如此行徑，這是對騎士精神的侮辱。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"THEMA_CS_ELECTRIC","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"단장님, 흔들리지 마십시오. 평기사들이 더 동요할 겁니다.","JPN":"団長、落ち着いてください。平騎士たちの動揺を煽ってしまいます。","ENG":"Do not get overwhelmed, Captain. The knight bachelors might get affected.","TWN":"團長，請不要動搖，否則會影響到平民騎士的士氣。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"THEMA_CS_ELECTRIC","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_HATE"},"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"지금 가장 돌파력이 우수한 태스크포스는 그쪽인 것 같군요.","JPN":"今最も突破力が優秀なタスクフォースはそちらのようですね。","ENG":"It seems like you are the TASKFORCE with the most breakthrough force.","TWN":"現在突破能力最強的特遣勢力就是你們了。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"THEMA_CS_ELECTRIC","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RIFLE_STATE_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"AIRBORNE_STATE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"적진 중심에 이 <color=#ffd34c>침식체 군집</color>을 지휘하는 개체가 있어요.","JPN":"敵陣の中心にこの<color=#ffd34c>侵食体の群れ</color>を指揮している個体がいます。","ENG":"There is an individual entity that's controlling the <color=#ffd34c>C.O. horde</color> in the middle of enemy territory.","TWN":"敵營中一定存在著指揮這個<color=#ffd34c>侵蝕體群</color>的個體。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"THEMA_CS_ELECTRIC","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RIFLE_STATE_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"AIRBORNE_STATE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"그 개체를 제압해야 합니다. 적어도 휘하 개체들을 통제하기 어렵게 만들어야 해요.","JPN":"その個体を制圧しなければなりません。少なくとも個体のコントロールを難しくする必要があります。","ENG":"We must take down that entity. We have to make it hard for it to control its underlings, at least.","TWN":"必須制伏那個個體。至少要讓他沒辦法指揮手下的個體才行。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"THEMA_CS_ELECTRIC","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RIFLE_STATE_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"AIRBORNE_STATE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"성공한다면 지금과 같이 통일된 움직임은 막을 수 있을 거랍니다.","JPN":"成功すれば今のように、統率の取れた動きはできなくできるでしょう。","ENG":"If we succeed, we will be able to stop their unified attacks.","TWN":"成功的話，就能阻止現在這樣統一的行動了。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"THEMA_CS_ELECTRIC","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RIFLE_STATE_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"AIRBORNE_STATE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NULL_NULL","text":{"KOREA":"……알겠다. 길을 여는 건 그대의 힘을 믿도록 하지.","JPN":"……わかった。道を開けるのは君の力を信じよう。","ENG":"...Affirmative. I'll count on you to make an opening.","TWN":"……好，開路的事我就先相信你。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"THEMA_CS_ELECTRIC","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"기사단, 돌격 태세로 진형을 정비하라!","JPN":"騎士団、突撃の態勢を取り、陣形を整えろ！","ENG":"Knights, change formation to charging position!","TWN":"騎士團，突擊隊形！"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"THEMA_CS_ELECTRIC","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"JAKE_DELTA_NEXT_NULL","text":{"KOREA":"크으……. 꽤 하는데, 멋쟁이 씨.","JPN":"くっ……結構やるな、イケメンさん。","ENG":"Damn... Not bad, Handsome.","TWN":"咳呃……不錯啊，帥哥。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"THEMA_CS_ELECTRIC","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NEXT_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"확실히 이방인 주제에 제법이군.","JPN":"確かに異邦人にしてはできるようだな。","ENG":"You do quite well yourself, for a outsider.","TWN":"作為外邦人，你們確實不錯。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"THEMA_CS_ELECTRIC","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"이미 적에게 실력을 인정 받았으니, 순순히 비켜 서지 그러나?","JPN":"すでに敵の私から実力を認められたんだから、大人しく退いてくれないか？","ENG":"Now that you earned my respect, why don't you step aside?","TWN":"既然實力已經獲得我的認可了，就乖乖地閃一邊去吧？"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"THEMA_CS_ELECTRIC","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"JAKE_DELTA_NEXT_NULL","text":{"KOREA":"이거 미안하군. 술집이었다면 자리야 얼마든지 비켜 줬을 텐데.","JPN":"悪いな。酒場だったらいくらでも退いてやれたんだが。","ENG":"Sorry to be a party pooper, but I'm not in a position to do so.","TWN":"抱歉，這可不行。如果是在酒吧裡，座位倒是可以隨便讓給你們。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"THEMA_CS_ELECTRIC","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"JAKE_DELTA_NEXT_NULL","text":{"KOREA":"오히려 그쪽이 비키지 그래. 지금이라도 항복하면 종신형으로 해결할 수도 있어.","JPN":"むしろそっちが退いたらどうだ。今降伏するなら終身刑で勘弁してやることもできる。","ENG":"Why don't YOU step aside? If you surrender now, the most you're going to get is a life sentence.","TWN":"還是你們退一步吧。現在投降的話，頂多判個無期徒刑。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"THEMA_CS_ELECTRIC","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"……무슨 뜻이지?","JPN":"……どういうことだ？","ENG":"...What do you mean?","TWN":"……什麼意思？"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"THEMA_CS_ELECTRIC","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"JAKE_DELTA_NEXT_NULL","text":{"KOREA":"나도 허세 부리는 편이라 잘 알거든.","JPN":"俺もカッコつけたい方だからわかるんだ。","ENG":"I'm also good at bluffing, you know.","TWN":"我也喜歡裝腔作勢，所以我很清楚。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"THEMA_CS_ELECTRIC","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"JAKE_DELTA_NEXT_NULL","text":{"KOREA":"그쪽도 어지간히 지쳤다는 것 말이야.","JPN":"そっちも相当疲れているんだろう。","ENG":"So I know that you're pretty worn out right now.","TWN":"你也已經快到極限了吧？"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"THEMA_CS_ELECTRIC","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NEXT_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"THEMA_CS_ELECTRIC","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"허튼 소리를 늘어놓는구나, 이방인.","JPN":"なに愚かなことを言っているんだ、異邦人。","ENG":"That's enough nonsense, outsider.","TWN":"真是滿口胡說八道，外邦人。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"THEMA_CS_ELECTRIC","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"나는 제국 신민들의 위에 서는 자다.","JPN":"私は帝国の臣民の上に立つ者だ。","ENG":"I stand above the subjects of the Empire.","TWN":"我是凌駕於帝國百姓之上的人。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"THEMA_CS_ELECTRIC","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"흔들리지 않고…… 흔들려서도 안 되는.","JPN":"強固であり……揺らぐことなど許されない。","ENG":"I am unshaken... I must be.","TWN":"不會動搖……也不可以動搖。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"THEMA_CS_ELECTRIC","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"JAKE_DELTA_NEXT_NULL","text":{"KOREA":"하하, 피차 인생 피곤하게 사는군.","JPN":"はは、そりゃぁ疲れる人生だな。","ENG":"Ha ha, you live life the hard way, don't you?","TWN":"哈哈，我們彼此的人生都過得相當累啊。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"THEMA_CS_ELECTRIC","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"JAKE_DELTA_NEXT_NULL","text":{"KOREA":"……웃?!","JPN":"……うっ！？","ENG":"...Ugh?!","TWN":"……唔？！"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NEXT_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"CHARLOTTE_ORDER_NULL_NULL","text":{"KOREA":"전하! 여기 계셨군요!","JPN":"殿下！　ここにいらっしゃいましたか！","ENG":"Your Highness! There you are!","TWN":"殿下！您在這裡！"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHARLOTTE_ORDER_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"마르티네즈 공……? 여긴 무슨 일인가?","JPN":"マルチネス卿……？　何故ここに？","ENG":"Marquise Martinez...? What brings you here?","TWN":"馬汀尼茲侯爵……？你來這裡有什麼事嗎？"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"CHARLOTTE_ORDER_NULL_NULL","text":{"KOREA":"전하를 모시러 왔습니다.","JPN":"殿下をお迎えに上がりました。","ENG":"I am here to escort you back.","TWN":"我是來護送殿下離開的。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHARLOTTE_ORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"CHARLOTTE_ORDER_NULL_NULL","text":{"KOREA":"알렌 경이 대열을 정비하고 있습니다. 우선 후방으로 몸을 피하셔야 합니다.","JPN":"バーミンガム卿が隊列を整えています。今はひとまず後方に退避すべきです。","ENG":"Sir Allen is adjusting the formation. You must fall back first.","TWN":"艾倫正在整頓隊伍，請您先去後方躲一躲。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHARLOTTE_ORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"아니. 마침 잘 되었다.","JPN":"いや。いいところに来た。","ENG":"No. Now is just the right time.","TWN":"不，你來得正好。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"마르티네즈 공, 그대에게 저 이방인의 상대를 맡기마.","JPN":"そなたにあの異邦人を任せる。","ENG":"Marquise Martinez, I will leave you to deal with that outsider.","TWN":"馬汀尼茲侯爵，那個外邦人就交給你對付了。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"CHARLOTTE_ORDER_NULL_NULL","text":{"KOREA":"네?","JPN":"はい？","ENG":"Huh?","TWN":"什麼？"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHARLOTTE_ORDER_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"CHARLOTTE_ORDER_NULL_NULL","text":{"KOREA":"무슨 말씀이십니까? 그럼 전하께서는…….","JPN":"どういうことでしょうか？　では殿下は……","ENG":"Pardon? Then what about you, Your High–","TWN":"您這是什麼意思？殿下……"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHARLOTTE_ORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"늑대가 포위를 벗어났다. 분명 곧장 평민 놈에게로 가겠지.","JPN":"狼が包囲から外れた。きっとまっすぐ平民のところに行くだろう。","ENG":"The Wolf got out of our boundaries. I assume she's headed towards the peasant.","TWN":"狼已經突出重圍，她肯定會直接去找平民那個傢伙。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"그러니 그대에게 뒤를 부탁하겠다. 샬롯 마르티네즈 공.","JPN":"だから後は任せた。シャーロット・マルチネス卿。","ENG":"That is why I leave the rest to you. Marquise Martinez.","TWN":"所以，後面的事就交給你了，夏洛特·馬汀尼茲侯爵。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"CHARLOTTE_ORDER_NULL_NULL","text":{"KOREA":"가시면 안 됩니다, 전하.","JPN":"行ってはなりません、殿下。","ENG":"You mustn't go, Your Highness.","TWN":"請您放心，殿下。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHARLOTTE_ORDER_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"CHARLOTTE_ORDER_NULL_NULL","text":{"KOREA":"늑대도, 발키리도, 구도자의 자손도. 아직 싸울 힘이 남아 있습니다.","JPN":"狼も、ヴァルキリーも、求道者の子孫も。まだ戦う力が残っています。","ENG":"The Wolf, Valkyrie, even the descendant of the Seeker of Truth... They are all still capable of fighting.","TWN":"不管是狼、女武神，還是求道者的後裔，我還有力氣戰鬥。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHARLOTTE_ORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"CHARLOTTE_ORDER_NULL_NULL","text":{"KOREA":"만에 하나 일이 잘못되기라도 하면…….","JPN":"万が一、殿下に何かがあれば……","ENG":"If things go wrong...","TWN":"萬一事情出了差錯……"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHARLOTTE_ORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"……언제까지 어리광 부릴 셈이지, 마르티네즈 공?","JPN":"……いつまで甘えるつもりだ、マルチネス卿？","ENG":"...When are you going to stop whining, Marquise Martinez?","TWN":"……你要耍賴到什麼時候，馬汀尼茲侯爵？"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"CHARLOTTE_ORDER_NULL_NULL","text":{"KOREA":"전하…….","JPN":"殿下……","ENG":"Your Highness...","TWN":"殿下……"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHARLOTTE_ORDER_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"그대를 거둔 건 순전히 내 변덕이었다.","JPN":"そなたを拾ったのはあくまで私の気まぐれだった。","ENG":"I have taken you in out of pure whim.","TWN":"接納你純粹是因為我的善變。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"그러니 더 이상, 충심이라는 핑계로 기대지 마라.","JPN":"だからこれ以上、忠誠心という口実で私に頼るな。","ENG":"Do not rely on me in the name of loyalty.","TWN":"所以，不要再以忠心為藉口依賴別人了。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"아무에게도. 절대로.","JPN":"誰にも、決してだ。","ENG":"Or anyone. Ever.","TWN":"也絕對不要依靠，任何人。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"CHARLOTTE_ORDER_NULL_NULL","text":{"KOREA":"……!","JPN":"……！","ENG":"...!","TWN":"……！"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHARLOTTE_ORDER_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"CHARLOTTE_ORDER_NULL_NULL","text":{"KOREA":"알겠…… 습니다. 전하.","JPN":"わかり……ました。殿下。","ENG":"Understood... Your Highness.","TWN":"我……知道了，殿下。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHARLOTTE_ORDER_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"CHARLOTTE_ORDER_NULL_NULL","text":{"KOREA":"선봉의 깃발을 쥔 자로서 저 자를, 이방인들을 반드시 저지하겠습니다.","JPN":"先鋒の旗を取った者としてあの者を、異邦人たちを必ず阻止してみせます。","ENG":"As the holder of the Banner of the Vanguard, I vow to take down the outsiders.","TWN":"作為舉著先鋒旗幟的人，我一定會阻止那個人，阻止那些外邦人。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHARLOTTE_ORDER_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"CHARLOTTE_ORDER_NULL_NULL","text":{"KOREA":"당신을 위해서가 아니라…… 저, 저 자신을 위해서.","JPN":"あなたのためではなく……わ、私自身のために。","ENG":"Not for you... b-but for myself.","TWN":"不是為了殿下……是，是為了我自己。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHARLOTTE_ORDER_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"……그래. 훌륭하다, 마르티네즈 공.","JPN":"……そうだ。見事だ、マルチネス卿。","ENG":"...Excellent. Well done, Marquise Martinez.","TWN":"……嗯，很好，馬汀尼茲侯爵。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"여지껏 수많은 귀족을 상대했지만, 그대와 같은 기개를 지닌 자는 만나지 못했다.","JPN":"これまで数多くの貴族を相手してきたが、そなたのような気概を持つ者には出会ったことがない。","ENG":"Among the countless aristocrats I have dealt with all my life, I have never seen anyone with more vigor than you.","TWN":"迄今為止我接觸過很多貴族，但還從來沒遇到過像你這樣有氣概的人。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"JAKE_DELTA_NEXT_NULL","text":{"KOREA":"이런, 용병 아가씨를 쫓아가려는 건가?","JPN":"おいおい、傭兵のお嬢ちゃんを追おうとしているのか？","ENG":"Oh dear, are you going after Miss Mercenary?","TWN":"哎呀，你是要去追傭兵小姐嗎？"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NEXT_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"JAKE_DELTA_NEXT_NULL","text":{"KOREA":"그렇다면 가만히 놔둘 수는……!","JPN":"ならば放っておくわけには……！","ENG":"I don't think I can let y–","TWN":"抱歉喔，我可不會……！"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"CHARLOTTE_ORDER_NULL_NULL","text":{"KOREA":"멋대로 굴게 내버려 두지 않겠어.","JPN":"勝手なマネはさせない。","ENG":"I won't let you go around as you please.","TWN":"我不會讓你胡鬧的。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHARLOTTE_ORDER_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"JAKE_DELTA_NEXT_NULL","text":{"KOREA":"……좋아, 등대털이범 아가씨. 우리 연이 꽤 깊은 것 같군.","JPN":"……よし、灯台荒らしのお嬢さん。俺たちは縁が深いようだ。","ENG":"...Very well, Lighthouse raider-lady. It looks like we're destined for each other, eh?","TWN":"……很好，燈塔小偷小姐，我們好像真的很有緣啊。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"CHARLOTTE_ORDER_NULL_NULL","text":{"KOREA":"닥쳐……. 네 놈 때문에……!","JPN":"黙れ……貴様のせいで……！","ENG":"Shut up... Because of you...!","TWN":"閉嘴……因為你……！"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHARLOTTE_ORDER_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"JAKE_DELTA_NEXT_NULL","text":{"KOREA":"멋쟁이 씨랑 작별 인사는 제대로 나눴나?","JPN":"イケメンさんにちゃんとさようならは言ったか？","ENG":"Did you farewell to your beloved Mr. Handsome?","TWN":"和帥哥好好告別了嗎？"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"CHARLOTTE_ORDER_NULL_NULL","text":{"KOREA":"그 입 닥쳐어어어어어!!","JPN":"黙れぇぇぇぇぇぇ！！","ENG":"I said SHUT UUUUUPPPPP!!","TWN":"我叫你！閉嘴！！"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHARLOTTE_ORDER_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"JAKE_DELTA_NEXT_NULL","text":{"KOREA":"투정 부린다고 세상 일이 잘 풀리진 않아.","JPN":"駄々をこねたからって、すべてが思い通りにいくわけじゃない。","ENG":"Being fussy won't save you.","TWN":"發脾氣並不能解決任何事。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"JAKE_DELTA_NEXT_NULL","text":{"KOREA":"그러니까 험한 꼴 보기 전에 항복하시지, 아가씨!","JPN":"だから痛い目に遭う前に降伏するんだな、お嬢さん！","ENG":"You better surrender before things go down, lady!","TWN":"所以，在變得更狼狽之前，我勸你還是投降吧，小姐！"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NEXT_NULL","face":"UNIT_SERIOUS"},"R":null}}}]`);export{e as default};